// procedural art — armoured winged lord wreathed in crackling storm-light
defineAnim('g_stormtyrant', 38, 40, 4, (p, f) => {
  const flap = (f === 1 || f === 3) ? 1 : 0;   // wing beat
  const hover = (f === 2) ? -1 : 0;            // hover bob
  const oy = hover;
  const arc = (f % 2) ? P.ice : P.blueL;       // crackle flicker

  // ---- great storm wings (drawn first, behind the body) ----
  const wy = 16 + oy - flap;
  // left wing
  p.line(11, wy, 1, wy - 6 - flap, P.blueD);
  p.line(11, wy, 2, wy + 2, P.blueD);
  p.line(1, wy - 6 - flap, 2, wy + 2, P.blueD);
  for (let i = 0; i < 4; i++) { p.line(11, wy, 2 + i, wy - 5 + i * 2 - flap, P.blue); }
  p.ellipse(6, wy - 2, 4, 3, P.blueD);
  p.ellipse(6, wy - 2, 2.4, 1.8, P.blue);
  // right wing (mirror)
  p.line(27, wy, 37, wy - 6 - flap, P.blueD);
  p.line(27, wy, 36, wy + 2, P.blueD);
  p.line(37, wy - 6 - flap, 36, wy + 2, P.blueD);
  for (let i = 0; i < 4; i++) { p.line(27, wy, 36 - i, wy - 5 + i * 2 - flap, P.blue); }
  p.ellipse(32, wy - 2, 4, 3, P.blueD);
  p.ellipse(32, wy - 2, 2.4, 1.8, P.blue);
  // arcs leaping between wingtips
  p.px(3, wy - 5 - flap, arc); p.px(35, wy - 5 - flap, arc);

  p.ellipse(19, 37 + oy, 11, 3, P.shadow);     // shadow

  // ---- armoured legs / taloned stance ----
  p.rect(12, 30 + oy, 5, 7, P.steelD);
  p.rect(21, 30 + oy, 5, 7, P.steelD);
  p.rect(13, 31 + oy, 3, 5, P.iron);
  p.rect(22, 31 + oy, 3, 5, P.iron);
  // talons
  p.px(12, 37 + oy, P.steelL); p.px(16, 37 + oy, P.steelL);
  p.px(21, 37 + oy, P.steelL); p.px(25, 37 + oy, P.steelL);

  // ---- torso (plated cuirass) ----
  p.rect(11, 15 + oy, 16, 17, P.steelD);
  p.rect(12, 16 + oy, 14, 14, P.iron);
  p.rect(13, 16 + oy, 12, 3, P.steelL);        // top edge sheen
  // storm core embedded in the chest
  p.ellipse(19, 22 + oy, 4.5, 4.5, P.blueD);
  p.ellipse(19, 22 + oy, 3.2, 3.2, P.blue);
  p.ellipse(19, 22 + oy, 1.8, 1.8, arc);
  p.px(19, 22 + oy, P.white);
  // arcs branching out of the core
  p.line(19, 18 + oy, 15, 16 + oy, arc); p.line(19, 18 + oy, 23, 16 + oy, arc);
  p.line(16, 25 + oy, 13, 29 + oy, P.blueL); p.line(22, 25 + oy, 25, 29 + oy, P.blueL);
  // belt
  p.hline(12, 25, 30 + oy, P.steelD);
  p.hline(13, 24, 31 + oy, P.gold);

  // ---- pauldrons + arms hurling bolts ----
  p.ellipse(10, 16 + oy, 4.5, 4.5, P.steelD);
  p.ellipse(28, 16 + oy, 4.5, 4.5, P.steelD);
  p.ellipse(10, 15 + oy, 2.8, 2.8, P.steel);
  p.ellipse(28, 15 + oy, 2.8, 2.8, P.steel);
  p.px(9, 14 + oy, P.steelL); p.px(27, 14 + oy, P.steelL);
  // gauntlet hands crackling with charge
  p.rect(7, 19 + oy, 3, 7, P.steelD); p.rect(28, 19 + oy, 3, 7, P.steelD);
  p.ellipse(8, 27 + oy, 2.6, 2.6, P.iron); p.ellipse(29, 27 + oy, 2.6, 2.6, P.iron);
  p.ellipse(8, 27 + oy, 1.4, 1.4, arc); p.ellipse(29, 27 + oy, 1.4, 1.4, arc);
  p.px(8, 27 + oy, P.white); p.px(29, 27 + oy, P.white);

  // ---- crowned helm ----
  p.ellipse(19, 9 + oy, 6, 6, P.steelD);
  p.ellipse(19, 9 + oy, 4.4, 4.4, P.iron);
  p.ellipse(19, 6 + oy, 3, 2, P.steelL);       // crest sheen
  // visor slit + burning eyes
  p.rect(14, 9 + oy, 10, 3, P.ink2);
  p.rect(15, 9 + oy, 3, 2, arc); p.rect(20, 9 + oy, 3, 2, arc);
  p.px(16, 9 + oy, P.white); p.px(21, 9 + oy, P.white);
  // jagged crown horns
  p.line(13, 5 + oy, 11, 0 + oy, P.gold); p.line(25, 5 + oy, 27, 0 + oy, P.gold);
  p.line(19, 3 + oy, 19, -1 + oy, P.goldL);
  p.px(11, 0 + oy, arc); p.px(27, 0 + oy, arc); p.px(19, -1 + oy, P.white);

  p.outline(P.ink);
}, { anchor: [19, 37], fps: 6 });

